code = """import json
import pandas as pd
import re

# Load data
with open(locals()['var_function-call-6016422251019821212'], 'r') as f:
    clinical_data = json.load(f)

# CDH1 mutated list
cdh1_mutated = pd.DataFrame(locals()['var_function-call-6559524650656627410'])
cdh1_barcodes = set(cdh1_mutated['ParticipantBarcode'].unique()) if not cdh1_mutated.empty else set()

# All sequenced list
with open(locals()['var_function-call-9292062724611195122'], 'r') as f:
    sequenced_list = json.load(f)
sequenced_barcodes = set(item['ParticipantBarcode'] for item in sequenced_list)

# Process clinical data
records = []
for entry in clinical_data:
    desc = entry.get('Patient_description', '')
    hist_type = entry.get('histological_type', 'None')
    
    # Extract barcode
    match = re.search(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', desc)
    if match:
        barcode = match.group(1)
        
        # Only consider if sequenced
        if barcode in sequenced_barcodes:
            # Determine mutation status
            has_mutation = barcode in cdh1_barcodes
            
            # Filter histological types
            # "only focusing on patients with known histological types"
            if hist_type not in ['None', '[Not Available]', 'Unknown', 'Other  specify', 'Mixed Histology (please specify)', 'Infiltrating Carcinoma NOS', 'Other']:
                 # Note: "Other specify" and "Mixed" might be excluded as they are not specific types, or maybe included. 
                 # The prompt says "known histological types". "Infiltrating Carcinoma NOS" is vague but known?
                 # Usually specific types are "Infiltrating Ductal Carcinoma", "Infiltrating Lobular Carcinoma", "Mucinous Carcinoma".
                 # I will exclude clearly unknown/other categories.
                 # Let's clean up a bit more.
                 if 'specify' in hist_type.lower() or 'nos' in hist_type.lower():
                     continue
                 
                 records.append({
                     'Barcode': barcode,
                     'Histological_Type': hist_type,
                     'Mutated': has_mutation
                 })

df = pd.DataFrame(records)

# Filter categories with marginal totals <= 10
# Marginal total of a category (Histological Type) is the number of patients in that type.
type_counts = df['Histological_Type'].value_counts()
valid_types = type_counts[type_counts > 10].index.tolist()
df_filtered = df[df['Histological_Type'].isin(valid_types)]

# Create contingency table
contingency_table = pd.crosstab(df_filtered['Histological_Type'], df_filtered['Mutated'])

# Calculate Chi-square manually
# Expected frequencies
row_totals = contingency_table.sum(axis=1)
col_totals = contingency_table.sum(axis=0)
grand_total = contingency_table.sum().sum()

chi2 = 0
for i in range(len(contingency_table)):
    for j in range(len(contingency_table.columns)):
        O_ij = contingency_table.iloc[i, j]
        E_ij = (row_totals.iloc[i] * col_totals.iloc[j]) / grand_total
        chi2 += ((O_ij - E_ij) ** 2) / E_ij

print("__RESULT__:")
print(json.dumps({
    "chi_square_statistic": chi2,
    "contingency_table": contingency_table.to_dict(),
    "valid_types": valid_types
}))"""

